package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;
import static edu.rice.hj.Module0.finish;
import static edu.rice.hj.Module1.async;
import static edu.rice.hj.Module1.doWork;

/**
 * A scorer that maximizes ideal parallelism using the anti-diagonal wavefront approach.
 *
 * <p>Cells on the same anti-diagonal are computed in parallel async tasks separated by
 * finish barriers. This yields CPL = xLength + yLength - 1 and Work = xLength * yLength.
 */
public class IdealParScoring extends AbstractDnaScoring {

    /**
     * The length of the first sequence.
     */
    private final int xLength;

    /**
     * The length of the second sequence.
     */
    private final int yLength;

    /**
     * The Smith-Waterman scoring matrix.
     */
    private final int[][] s;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(IdealParScoring::new);
        scoringRunner.start("IdealParScoring", args);
    }

    /**
     * Creates a new IdealParScoring.
     *
     * <p>Allocates the full scoring matrix and initializes boundary conditions.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public IdealParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }
        this.xLength = xLength;
        this.yLength = yLength;
        this.s = new int[xLength + 1][yLength + 1];
        for (int i = 1; i <= xLength; i++) {
            s[i][0] = getScore(1, 0) * i;
        }
        for (int j = 1; j <= yLength; j++) {
            s[0][j] = getScore(0, 1) * j;
        }
    }

    /**
     * Parallel Smith-Waterman using anti-diagonal wavefront to maximize ideal parallelism.
     *
     * <p>Each anti-diagonal is processed with a finish barrier; all cells within a diagonal
     * run in parallel async tasks, each calling doWork(1). CPL = xLength + yLength - 1.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        for (int d = 2; d <= xLength + yLength; d++) {
            final int diag = d;
            final int iStart = Math.max(1, diag - yLength);
            final int iEnd = Math.min(xLength, diag - 1);
            finish(() -> {
                for (int i = iStart; i <= iEnd; i++) {
                    final int iLoc = i;
                    final int jLoc = diag - i;
                    async(() -> {
                        doWork(1);
                        final char xChar = x.charAt(iLoc - 1);
                        final char yChar = y.charAt(jLoc - 1);
                        final int diagVal = s[iLoc - 1][jLoc - 1]
                            + getScore(charMap(xChar), charMap(yChar));
                        final int topVal = s[iLoc - 1][jLoc] + getScore(charMap(xChar), 0);
                        final int leftVal = s[iLoc][jLoc - 1] + getScore(0, charMap(yChar));
                        s[iLoc][jLoc] = Math.max(diagVal, Math.max(leftVal, topVal));
                    });
                }
            });
        }
        return s[xLength][yLength];
    }

}

package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;
import static edu.rice.hj.Module1.forallChunked;

/**
 * A scorer that achieves real parallel speedup using the anti-diagonal wavefront approach.
 *
 * <p>Processes anti-diagonals sequentially; within each diagonal, cells are computed
 * in parallel using forallChunked which distributes work across available worker threads.
 */
public class UsefulParScoring extends AbstractDnaScoring {

    /**
     * The length of the first sequence.
     */
    private final int xLength;

    /**
     * The length of the second sequence.
     */
    private final int yLength;

    /**
     * The Smith-Waterman scoring matrix.
     */
    private final int[][] s;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(UsefulParScoring::new);
        scoringRunner.start("UsefulParScoring", args);
    }

    /**
     * Creates a new UsefulParScoring.
     *
     * <p>Allocates the full scoring matrix and initializes boundary conditions.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public UsefulParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }
        this.xLength = xLength;
        this.yLength = yLength;
        this.s = new int[xLength + 1][yLength + 1];
        for (int i = 1; i <= xLength; i++) {
            s[i][0] = getScore(1, 0) * i;
        }
        for (int j = 1; j <= yLength; j++) {
            s[0][j] = getScore(0, 1) * j;
        }
    }

    /**
     * Efficient parallel Smith-Waterman using anti-diagonal wavefront with forallChunked.
     *
     * <p>For each anti-diagonal, uses forallChunked to distribute cell computations across
     * P worker threads. The implicit barrier in forallChunked ensures correct ordering between
     * diagonals. Targets at least 8x speedup on 16 cores for O(10^4) length strings.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        for (int d = 2; d <= xLength + yLength; d++) {
            final int diag = d;
            final int iStart = Math.max(1, diag - yLength);
            final int iEnd = Math.min(xLength, diag - 1);
            forallChunked(iStart, iEnd, (i) -> {
                final int j = diag - i;
                final char xChar = x.charAt(i - 1);
                final char yChar = y.charAt(j - 1);
                final int diagVal = s[i - 1][j - 1] + getScore(charMap(xChar), charMap(yChar));
                final int topVal = s[i - 1][j] + getScore(charMap(xChar), 0);
                final int leftVal = s[i][j - 1] + getScore(0, charMap(yChar));
                s[i][j] = Math.max(diagVal, Math.max(leftVal, topVal));
            });
        }
        return s[xLength][yLength];
    }

}

package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;
import static edu.rice.hj.Module1.forallChunked;

/**
 * A scorer that uses O(min(|X|, |Y|)) memory by maintaining only three rolling diagonal arrays.
 *
 * <p>Instead of allocating the full S matrix, this implementation stores only three consecutive
 * anti-diagonals at a time. Cells within each diagonal are computed in parallel using
 * forallChunked. This allows scoring of O(10^5) length sequences without O(n^2) memory.
 */
public class SparseParScoring extends AbstractDnaScoring {

    /**
     * The length of the first sequence.
     */
    private final int xLength;

    /**
     * The length of the second sequence.
     */
    private final int yLength;

    /**
     * First rolling diagonal buffer.
     */
    private final int[] diagA;

    /**
     * Second rolling diagonal buffer.
     */
    private final int[] diagB;

    /**
     * Third rolling diagonal buffer.
     */
    private final int[] diagC;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(SparseParScoring::new);
        scoringRunner.start("SparseParScoring", args);
    }

    /**
     * Creates a new SparseParScoring.
     *
     * <p>Allocates only three rolling arrays of size min(xLength, yLength) + 1 instead of
     * the full O(xLength * yLength) matrix. Memory usage is O(min(|X|, |Y|)).
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public SparseParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }
        this.xLength = xLength;
        this.yLength = yLength;
        final int maxDiagLen = Math.min(xLength, yLength) + 1;
        this.diagA = new int[maxDiagLen];
        this.diagB = new int[maxDiagLen];
        this.diagC = new int[maxDiagLen];
    }

    /**
     * Sparse parallel Smith-Waterman using rolling diagonal arrays and forallChunked.
     *
     * <p>Processes diagonals from d=0 to d=xLength+yLength, maintaining only three arrays
     * for diagonals d-2, d-1, and d. Within each diagonal, forallChunked parallelizes
     * cell computations across available threads. Memory usage is O(min(|X|, |Y|)).
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        int[] prevTwo = diagA;
        int[] prevOne = diagB;
        int[] currDiag = diagC;

        for (int d = 0; d <= xLength + yLength; d++) {
            final int diag = d;
            final int iStart = Math.max(0, diag - yLength);
            final int iEnd = Math.min(xLength, diag);
            final int diagLen = iEnd - iStart + 1;
            final int iStartPrevOne = Math.max(0, diag - 1 - yLength);
            final int iStartPrevTwo = Math.max(0, diag - 2 - yLength);
            final int[] finalPrevTwo = prevTwo;
            final int[] finalPrevOne = prevOne;
            final int[] finalCurrDiag = currDiag;

            forallChunked(0, diagLen - 1, (k) -> {
                final int i = iStart + k;
                final int j = diag - i;
                if (i == 0) {
                    finalCurrDiag[k] = j * getScore(0, 1);
                } else if (j == 0) {
                    finalCurrDiag[k] = i * getScore(1, 0);
                } else {
                    final int prevDiagIdx = (i - 1) - iStartPrevTwo;
                    final int prevTopIdx = (i - 1) - iStartPrevOne;
                    final int prevLeftIdx = i - iStartPrevOne;
                    final char xChar = x.charAt(i - 1);
                    final char yChar = y.charAt(j - 1);
                    final int diagVal = finalPrevTwo[prevDiagIdx]
                        + getScore(charMap(xChar), charMap(yChar));
                    final int topVal = finalPrevOne[prevTopIdx] + getScore(charMap(xChar), 0);
                    final int leftVal = finalPrevOne[prevLeftIdx] + getScore(0, charMap(yChar));
                    finalCurrDiag[k] = Math.max(diagVal, Math.max(leftVal, topVal));
                }
            });

            final int[] temp = prevTwo;
            prevTwo = prevOne;
            prevOne = currDiag;
            currDiag = temp;
        }

        return prevOne[0];
    }

}

