    19→    private static long runPerfTestHelper(Runnable preRunnable, CheckedFunction runnable, Runnable postRunnable,
    20→            final int nruns) throws SuspendableException {
    21→        final long[] run_times = new long[nruns];
    22→        for (int r = 0; r < nruns; r++) {
