    24→                preRunnable.run();
    25→            }
    26→            final long start = System.currentTimeMillis();
    27→            runnable.apply();
    28→            final long elapsed = System.currentTimeMillis() - start;
    29→
    30→            if (postRunnable != null) {
    31→                postRunnable.run();
    32→            }
    33→
    34→            run_times[r] = elapsed;
    35→        }
    36→
    37→        Arrays.sort(run_times);
